import { useEffect, useState } from "react";

const MOBILE_SLIDES = [
  "https://res.cloudinary.com/dbtkfjrvd/image/upload/v1776904605/photo_2026-04-23_01-35-15_szpcpu.jpg",
  "https://res.cloudinary.com/dbtkfjrvd/image/upload/v1776904605/photo_2026-04-23_01-35-12_tg5fco.jpg",
  "https://res.cloudinary.com/dbtkfjrvd/image/upload/v1776904605/photo_2026-04-23_01-35-08_pxqhqa.jpg",
];

const DESKTOP_SLIDES = [
  "https://res.cloudinary.com/dbtkfjrvd/image/upload/v1776904604/photo_2026-04-23_01-35-31_ntcz0l.jpg",
];

const BREAKPOINT = 768;
const INTERVAL_MS = 5500;

export default function Hero() {
  const [isMobile, setIsMobile] = useState(
    () => typeof window !== "undefined" && window.innerWidth < BREAKPOINT
  );
  const [index, setIndex] = useState(0);

  const slides = isMobile ? MOBILE_SLIDES : DESKTOP_SLIDES;

  useEffect(() => {
    const mq = window.matchMedia(`(max-width: ${BREAKPOINT - 1}px)`);
    const onChange = () => setIsMobile(mq.matches);
    onChange();
    mq.addEventListener("change", onChange);
    return () => mq.removeEventListener("change", onChange);
  }, []);

  useEffect(() => {
    setIndex(0);
  }, [isMobile]);

  useEffect(() => {
    if (slides.length <= 1) return undefined;
    const id = window.setInterval(() => {
      setIndex((i) => (i + 1) % slides.length);
    }, INTERVAL_MS);
    return () => window.clearInterval(id);
  }, [slides.length]);

  const go = (dir) => {
    setIndex((i) => {
      const n = slides.length;
      if (n === 0) return 0;
      return (i + dir + n) % n;
    });
  };

  return (
    <section className="hero-carousel" aria-roledescription="carousel" aria-label="Badee — bannières">
      <div className="hero-carousel-viewport">
        {slides.map((src, i) => (
          <img
            key={src}
            src={src}
            alt=""
            className={`hero-carousel-slide${i === index ? " is-active" : ""}`}
            loading={i === 0 ? "eager" : "lazy"}
            decoding="async"
          />
        ))}
        <div className="hero-carousel-controls" aria-hidden="true">
          <button type="button" className="hero-carousel-arrow hero-carousel-arrow--prev" onClick={() => go(-1)} aria-label="Image précédente" />
          <button type="button" className="hero-carousel-arrow hero-carousel-arrow--next" onClick={() => go(1)} aria-label="Image suivante" />
        </div>
      </div>
      <div className="hero-carousel-dots" role="tablist" aria-label="Choisir une bannière">
        {slides.map((_, i) => (
          <button
            key={i}
            type="button"
            role="tab"
            aria-selected={i === index}
            aria-label={`Bannière ${i + 1} sur ${slides.length}`}
            className={`hero-carousel-dot${i === index ? " is-active" : ""}`}
            onClick={() => setIndex(i)}
          />
        ))}
      </div>
    </section>
  );
}
